using Microsoft.EntityFrameworkCore;

class CosmosQuery
{
    // EF Core 9 Cosmos provider no longer supports synchronous I/O — use async.
    async Task FindProductsAsync(ProductContext ctx)
    {
        // Direct Cosmos SQL — safe because we configured HasDiscriminator("Discriminator")
        // to keep the old property name. No change needed here.
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        // Sync ToList() throws in EF Core 9 Cosmos; use ToListAsync().
        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

